export const config = {
  port: parseInt(process.env.PORT || '3000'),
  emailFrom: process.env.EMAIL_FROM || 'noreply@app.com',
  smtpHost: process.env.SMTP_HOST || 'localhost',
  slackWebhookUrl: process.env.SLACK_WEBHOOK_URL || '',
};

import { NotificationChannel } from './notificationService';

export class SlackChannel implements NotificationChannel {
  name = 'slack';

  constructor(private webhookUrl: string) {
    if (!webhookUrl) {
      throw new Error('Slack webhook URL is required');
    }
  }

  async send(message: string, metadata?: Record<string, unknown>): Promise<void> {
    const payload = {
      text: message,
      blocks: [
        {
          type: 'section',
          text: { type: 'mrkdwn', text: `*${message}*` },
        },
      ],
    };

    if (metadata?.event) {
      payload.blocks.push({
        type: 'section',
        text: { type: 'mrkdwn', text: `Event: \`${metadata.event}\`` },
      });
    }

    const response = await fetch(this.webhookUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
    });

    if (!response.ok) {
      throw new Error(`Slack webhook failed: ${response.status} ${response.statusText}`);
    }
  }
}

