describe('SlackChannel', () => {
  const { SlackChannel } = require('../src/services/slackChannel');

  test('throws if webhook URL is empty', () => {
    expect(() => new SlackChannel('')).toThrow('Slack webhook URL is required');
  });

  test('sends formatted payload to webhook', async () => {
    const mockFetch = jest.fn().mockResolvedValue({ ok: true });
    global.fetch = mockFetch;

    const channel = new SlackChannel('https://hooks.example.com/test');
    await channel.send('New signup: Alice', { event: 'signup' });

    expect(mockFetch).toHaveBeenCalledWith(
      'https://hooks.example.com/test',
      expect.objectContaining({
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
      })
    );

    const body = JSON.parse(mockFetch.mock.calls[0][1].body);
    expect(body.text).toBe('New signup: Alice');
    expect(body.blocks).toHaveLength(2);
  });

  test('throws on non-ok response', async () => {
    global.fetch = jest.fn().mockResolvedValue({ ok: false, status: 403, statusText: 'Forbidden' });

    const channel = new SlackChannel('https://hooks.example.com/test');
    await expect(channel.send('test')).rejects.toThrow('Slack webhook failed: 403');
  });
});
